const items = $input.all();

// Filtrer ET mapper en une seule opération
const donnees = items
    .filter(item => {
        const ecart = item.json.Ecart;
        return Math.abs(parseFloat(ecart)) <= 1 && item.json.ModePaiement === "LCR" ;
    })
    .map(item => {
        const row = item.json;
        return {
            Code_Frs: row.CodeFournisseur|| "",
            N_Facture: row.NumFacture || "",
            Refference: row.Reference,
            Montant: row.ResteAPayer || "",
            TVA: row.MontantTVA || "",
            type_regelement: 1
        };
    });

return [{
    json: {
        donnees: JSON.stringify(donnees),  // ← stringify it here
        email_expediteur: "astitoumde@gmail.com",
        headless: false
    }
}];

// Avant l'envoi, assurez-vous que toutes les données sont dans le tableau
const allData = $input.all()[0].json.donnees; // ou votre source de données
const requestBody = {
  donnees: allData.map(item => ({
    N_Facture: item.N_Facture,
    Reference: item.Reference,
    Montant: item.Montant,
    TVA: item.TVA,
    type_regelement: item.type_regelement
  })),
  email_expediteur: "votre.email@example.com", // ou null
  headless: false
};

return [{ json: requestBody }];
